 42→  return (
 43→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 44→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 45→      <line
 46→        x1="30"
 47→        y1="30"
 48→        x2="42"
