182→interface QuicklinkFormState {
183→  name: string;
184→  link: string;
185→  type: QuicklinkType;
186→  application: string;
187→}
188→
189→const INITIAL_FORM: QuicklinkFormState = {
190→  name: '',
191→  link: '',
192→  type: 'url',
193→  application: '',
194→};
195→
196→const TYPE_OPTIONS = [
197→  {
198→    label: 'URL',
199→    value: 'url',
200→  },
201→  {
202→    label: 'File Path',
203→    value: 'file',
204→  },
205→  {
206→    label: 'Deep Link',
207→    value: 'deeplink',
208→  },
209→];
210→
211→interface EditQuicklinkViewProps {
212→  quicklink?: QuicklinkEntry;
213→  onSubmit: (form: QuicklinkFormState) => void;
214→}
215→
216→function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
217→  const [form, setForm] = useState<QuicklinkFormState>(() => {
218→    if (quicklink) {
219→      return {
220→        name: quicklink.name,
221→        link: quicklink.link,
222→        type: quicklink.type,
223→        application: quicklink.application ?? '',
224→      };
225→    }
226→    return INITIAL_FORM;
227→  });
228→  const [errors, setErrors] = useState<
229→    Partial<Record<keyof QuicklinkFormState, string>>
230→  >({});
231→
232→  const handleSubmit = useCallback(() => {
233→    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
234→    if (!form.name.trim()) {
235→      newErrors.name = 'Name is required';
236→    }
237→    if (!form.link.trim()) {
238→      newErrors.link = 'Link is required';
239→    }
240→    setErrors(newErrors);
241→    if (Object.keys(newErrors).length > 0) return;
242→    onSubmit(form);
243→  }, [
244→    form,
245→    onSubmit,
246→  ]);
247→
248→  useKeyboardShortcut(
249→    {
250→      key: 'Enter',
251→      meta: true,
252→    },
253→    handleSubmit,
254→  );
255→
256→  return (
257→    <Form onSubmit={handleSubmit}>
258→      <FormTextField
259→        label="Name"
260→        value={form.name}
261→        onChange={v =>
262→          setForm(prev => ({
263→            ...prev,
264→            name: v,
265→          }))
266→        }
267→        placeholder="e.g. GitHub Dashboard"
268→        error={errors.name}
269→        autoFocus
270→      />
271→      <FormTextField
272→        label="Link"
273→        value={form.link}
274→        onChange={v =>
275→          setForm(prev => ({
276→            ...prev,
277→            link: v,
278→          }))
279→        }
280→        placeholder="e.g. https://github.com or ~/Documents"
281→        description="Use {query} as placeholder for dynamic input"
282→        error={errors.link}
283→      />
284→      <FormDropdown
285→        label="Type"
286→        value={form.type}
287→        onChange={v =>
288→          setForm(prev => ({
289→            ...prev,
290→            type: v as QuicklinkType,
291→          }))
292→        }
293→        options={TYPE_OPTIONS}
294→      />
295→      <FormTextField
296→        label="Open With"
297→        value={form.application}
298→        onChange={v =>
299→          setForm(prev => ({
300→            ...prev,
301→            application: v,
302→          }))
303→        }
304→        placeholder="e.g. Safari (optional)"
305→        description="Application to open the link with"
306→      />
307→    </Form>
308→  );
309→}
